{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits for core SHIP counseling services; available to anyone eligible for Medicare (typically age 65+ or under 65 with certain disabilities), family members, caregivers, and those soon to be eligible. Separate assistance programs helped by SHIP (e.g., Medicare Savings Programs via Indiana Medicaid) have income limits: QMB at or below 150% FPL (e.g., ~$22,590/year for individual in 2026); SLMB/QI at or below 185% FPL (~$27,870/year for individual); exact FPL varies annually by household size—no full table in sources[2][4]. If income < $2,500/month with limited assets, may qualify for help with uncovered Medicare costs[2].",
    "asset_limits": "No asset limits for core SHIP counseling. For related low-income assistance programs (e.g., via Medicaid), limited resources apply but specifics not detailed; consult SHIP for current thresholds[2][4].",
    "other_requirements": ["Must be eligible for Medicare or soon eligible", "Family members/caregivers of Medicare beneficiaries also qualify", "Indiana resident[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, impartial one-on-one counseling (in-person, phone, Zoom); plan comparison/enrollment (Medicare, Supplements, Advantage, Part D, Long Term Care); education on Medicare rights/claims/appeals; applications for low-income subsidies (e.g., MSP, LIS); referrals; group presentations; no direct financial aid or fixed hours/dollars—unlimited as needed via trained volunteer counselors[2][5][6].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-452-4800 (statewide), TTY: 1-866-846-0139[8]", "Website: https://www.in.gov/ship/[2][8]", "In-person/remote: Local providers e.g., Central Indiana (317-803-6131 via CICOA), Porter County (219-464-1028 or SHIP@portercountyacs.org)[4][5]", "No specific online form or mail address listed; contact to schedule counseling/appointments[2]"],
    "processing_time": "Immediate counseling availability by phone; appointments scheduled as needed, no formal processing[1][5].",
    "waitlist": null,
    "forms": ["No specific SHIP enrollment form; helps with Medicare/Medicaid applications (e.g., MSP, LIS) during counseling[2][6]"],
    "documents": ["Medicare card, current insurance details, income/asset info if applying for subsidies; not required for initial counseling[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Indiana residents only",
    "regional_variations": "Delivered via local providers (e.g., CICOA in Central Indiana, Porter County Aging & Community Services); contact numbers/offices vary by area but services consistent statewide[3][4][5].",
    "offices_or_providers": ["Indiana Dept. of Insurance, 311 W Washington St, 2nd Floor, Indianapolis IN 46204[3]", "Local e.g., CICOA (Central IN), Porter County ACS[4][5]"]
  },
  "official_source": "https://www.in.gov/ship/",
  "gotchas": ["SHIP itself is free counseling only—not direct financial aid or healthcare; confuses with Medicare Savings Programs (MSP) it helps apply for, which have strict income/asset tests[2][4]", "Not affiliated with insurers—impartial, doesn't sell plans[2][6]", "Peak demand during Open Enrollment (Oct 15-Dec 7); contact early[5]", "Separate from Indiana Medicaid low-income programs it assists with[4]"],
  "data_shape_notes": "no income test for counseling; helps apply for tiered subsidy programs (QMB/SLMB) with FPL-based limits; delivered statewide via regional volunteer networks"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Resident of a nursing home or licensed assisted living facility in Indiana.", "Anyone can contact on behalf of a resident: residents themselves, relatives, friends, facility staff, or community members concerned about resident welfare."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, confidential advocacy services including: receiving and investigating complaints; assisting with resolution of issues like quality of care (e.g., call lights not answered, medication errors, poor hygiene), violations of rights (e.g., privacy, dignity, emotional/verbal abuse), transfers/discharges (e.g., improper discharge, Medicaid discrimination); facility visits to monitor resident rights; resident-directed support under federal and state law. No specific dollar amounts, hours, or tiers.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: State Ombudsman 1-800-622-4484 or 317-232-7134.", "Email: Via local or state ombudsman program (specific addresses not listed; contact via phone).", "Mail: Office of the Long Term Care Ombudsman, 402 West Washington Street, Room W451, Post Office Box 7083, MS 27, Indianapolis, Indiana 46207-7083.", "In-person: Local ombudsman offices across the state (contact state line for nearest).", "No formal application form for services; contact to file a complaint or request assistance directly."],
    "processing_time": "Not specified for service requests; volunteer certification process takes 4-6 weeks (application review, interview, background/reference checks, approval).",
    "waitlist": null,
    "forms": ["No specific forms for receiving services; volunteer applicants submit application with 3 references and signed background check authorization."],
    "documents": ["No documents required to request services. For volunteers: references, background check authorization. Residents may need to provide consent for record access if capable, or physician determination if incapable."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of nursing homes and licensed assisted living facilities; home care services authorized by statute but not funded or provided statewide.",
    "regional_variations": "Delivered through a network of local offices across Indiana that recruit, train, and manage certified ombudsmen; specific wait times or providers may vary by locality but no details provided.",
    "offices_or_providers": ["State office: 402 West Washington Street, Room W451, Indianapolis.", "Local offices statewide (contact 1-800-622-4484 for nearest)."]
  },
  "official_source": "https://www.in.gov/ombudsman/long-term-care-ombudsman/overview/",
  "gotchas": ["Not a direct service provider (e.g., no healthcare, financial aid, or placement); purely advocacy and complaint resolution.", "Services resident-directed and confidential; ombudsman access to records requires resident/client consent or legal determination of incapacity.", "Primarily for long-term care facilities; home care complaints authorized but not actively handled due to lack of funding.", "Anyone can contact, but focuses on protecting rights in nursing homes and licensed assisted living.", "Volunteering has separate requirements (18+, background check, no conflicts of interest) and is not required for receiving services."],
  "data_shape_notes": "no income test; advocacy-only (no financial benefits); statewide via local offices; facility-residents only (home care statutorily authorized but unfunded)"
}

{
  "name": "Structured Family Caregiving",
  "eligibility": {
    "age": 18,
    "income_limits": "Care recipient must qualify for Indiana Medicaid A&D (Aged & Disabled) Waiver or TBI Waiver, which has income limit of generally $2,982/month in 2026 for applicant (non-applicant spouse income not counted); asset limit of $2,000 for applicant (higher Community Spouse Resource Allowance for non-applicant spouse if married). Limits vary by household size via Medicaid rules—no specific SFC table provided[1][2][5].",
    "asset_limits": "Medicaid waiver standard: $2,000 countable assets for applicant (exempt: primary home if intent to return, one vehicle, personal belongings, burial plots; jointly owned assets considered for married couples with spousal allowances)[2].",
    "other_requirements": [
      "Care recipient: Indiana resident, eligible for A&D or TBI Medicaid Waiver, needs assistance with at least 2-3 ADLs (e.g., bathing, dressing, eating, toileting, transferring), requires daily support/supervision, prefers home-based care over institution[1][3][4][5].",
      "Caregiver: 18+ years old, live in same household as recipient, pass criminal background check (no abuse/neglect/exploitation history), complete assessment/training, willing/able to provide daily care; can be family, friend, or neighbor (not spouse per some providers; not required to be family or RN)[1][2][3][4][5][6]."
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "Daily rate/per diem payment to caregiver based on needs assessment level (Level 1: 1-20 hours/week; Level 2: 21-40 hours/week; Level 3: 41+ hours/week until July 1, 2024—thereafter needs-based); up to ~$2,000/month possible; plus ongoing training/support from case manager/RN[1][4][7][8].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact Indiana FSSA Division of Aging at 1-800-457-8283 or local Area Agency on Aging (AAA)[1][4].",
      "Work with care manager/provider (e.g., FreedomCare, ResCare, Careforth, Paid.care) for assessment/enrollment[1][4][5][8].",
      "No specific online URL or form listed; case manager submits application after assessment[1]."
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not specified; waiver eligibility may involve waitlists.",
    "forms": ["No specific form name/number identified; involves functional needs assessment and waiver application."],
    "documents": ["Medicaid/waiver eligibility proof, background check documents, functional needs assessment, proof of residency/cohabitation (inferred from process)[1][4]."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None statewide; requires Indiana residency and waiver eligibility.",
    "regional_variations": "Administered via local Area Agencies on Aging (AAAs); providers like ResCare, FreedomCare operate statewide but may vary by region; no specific wait time/provider differences noted[1][4][9].",
    "offices_or_providers": ["Local Area Agency on Aging (AAA), FSSA Division of Aging; providers: ResCare, FreedomCare, Careforth, Paid.care[1][4][5][8][9]."]
  },
  "official_source": "https://www.in.gov/fssa/da/ (FSSA Division of Aging; FAQ: https://www.in.gov/fssa/files/SFC-FAQ-Families-FINAL.pdf)[1][7]",
  "gotchas": [
    "Tied to A&D or TBI Medicaid Waiver eligibility (financial/functional needs assessed separately; potential waitlists).",
    "Caregiver must live in same household and pass background/training; spouse often ineligible[1][2][4].",
    "Payment levels determined by care manager assessment (not fixed hours/dollars upfront)[7].",
    "Cannot double-dip: primary caregiver unavailable for separate home health aide pay[7].",
    "Until July 1, 2024, levels based on prior attendant care hours for under-18s[7]."
  ],
  "data_shape_notes": "Requires separate Medicaid A&D/TBI Waiver approval first; tiered daily rates by assessed care level (1-3); statewide via local AAAs/providers; no standalone income table—uses Medicaid limits."
}

{
  "name": "Community and Home Options to Institutional Care for the Elderly and Disabled (CHOICE)",
  "eligibility": {
    "age": "60 or older, or any age with a disability",
    "income_limits": "No income limits or exclusions; financial eligibility does not exclude based on income. Certain medical expenses may be excluded from income calculations.[8]",
    "asset_limits": "No asset limits specified; certain medical expenses may not be counted in asset calculations.[8]",
    "other_requirements": [
      "At risk of losing independence due to impairments in Activities of Daily Living (ADLs) such as bathing, dressing, eating, toileting, transferring, mobility, medication management.",
      "Severe, complex, and unstable medical conditions or substantial medical conditions limiting ADLs.",
      "Long-term or lifelong limitations (e.g., dependence on others for personal care, communication issues, learning/maintaining self-care, mobility between environments, decision-making/judgment).",
      "Determined via Long-Term Care Services Eligibility Form.[7][8]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "In-home support services to help elderly (60+) and disabled individuals remain at home instead of institutional care. Specific services address ADLs including bathing, eating, dressing, toileting, medication setup; not comprehensive healthcare coverage.[7][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Phone: Call local Area Agency on Aging (AAA) or 1-800-713-9023 to identify local office and request application.[8]",
      "In-person: Contact local AAA for the county of residence.[7][8]"
    ],
    "processing_time": "Not specified",
    "waitlist": "Waiting lists managed regionally by local AAAs; varies by area.[8]",
    "forms": ["Long-Term Care Services Eligibility Form[7]"],
    "documents": ["Documentation of medical conditions, ADLs limitations, disability status if applicable[7][8]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in all 92 Indiana counties[8]",
    "regional_variations": "Administered regionally by local Area Agencies on Aging (AAAs); different providers, offices, and wait times by county/region. Use AAA map for local contact.[8]",
    "offices_or_providers": ["Local Area Agency on Aging (AAA) offices; map at https://www.in.gov/fssa/da/files/AAA_Map.pdf[8]"]
  },
  "official_source": "https://www.in.gov/fssa/da/files/AAA_Map.pdf (AAA map); program details via local AAAs or 1-800-713-9023[8]",
  "gotchas": [
    "Does not provide comprehensive healthcare coverage or automatic Medicaid enrollment; cannot use funds if Medicare/Medicaid covers needs.[8]",
    "Must contact local AAA—program is regionally administered, not centralized.[7][8]",
    "Eligibility focuses on functional ADL impairments and risk of institutionalization, not just age or diagnosis.[7]",
    "Waiting lists common due to regional availability.[8]"
  ],
  "data_shape_notes": "No income/asset tests; eligibility driven by ADL/medical needs assessment; administered by 16 regional AAAs across 92 counties with varying waitlists and providers."
}
